iterations.plan:
pred GeneratedPlan {
  some f: Facility, d: DiarrhealIncident {
    f.activeBiohazardIncident = d
    d.facShockTenthPPM >= 200
    d.ctValueAchieved = True
    d.filterBackwashedToWaste = True
    d.poolClosedHours >= 13
    d.reopenAllowed = True
    d.minutesSinceIncident = 60
    some p: Patron, z: f.zones | p.inWater = z
  }
}
